import React, { useState } from 'react';
import { View, Text, Switch, TextInput, StyleSheet, ScrollView } from 'react-native';
import { useTheme } from '../hooks/useTheme';
import { spacing, fontSize, borderRadius } from '../theme';

export default function SettingsScreen() {
  const theme = useTheme();
  const [darkMode, setDarkMode] = useState(false);
  const [name, setName] = useState('');

  return (
    <ScrollView
      style={[styles.container, { backgroundColor: theme.background }]}
      contentContainerStyle={styles.content}
    >
      <Text style={[styles.title, { color: theme.text }]}>Settings</Text>

      <View style={[styles.row, { borderBottomColor: theme.border }]}>
        <Text style={[styles.label, { color: theme.text }]}>Dark Mode</Text>
        <Switch value={darkMode} onValueChange={setDarkMode} />
      </View>

      <View style={styles.field}>
        <Text style={[styles.label, { color: theme.text }]}>Your Name</Text>
        <TextInput
          style={[styles.input, { backgroundColor: theme.surface, color: theme.text, borderColor: theme.border }]}
          value={name}
          onChangeText={setName}
          placeholder="Enter your name"
          placeholderTextColor={theme.textSecondary}
        />
      </View>
    </ScrollView>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1 },
  content: { padding: 24 },
  title: { fontSize: 24, fontWeight: '700', marginBottom: 24 },
  row: { flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center', paddingVertical: 16, borderBottomWidth: 1 },
  label: { fontSize: 16 },
  field: { marginTop: 24 },
  input: { marginTop: 8, borderWidth: 1, borderRadius: 8, padding: 12, fontSize: 16 },
});

import React from 'react';
import SettingsScreen from '../screens/SettingsScreen';

export default function Settings() {
  return <SettingsScreen />;
}

